<?php

class DSS_DsBeforeAfterSlider extends DiviExtension {

	/**
	 * The gettext domain for the extension's translations.
	 *
	 * @since 1.0.0
	 *
	 * @var string
	 */
	public $gettext_domain = 'dss-ds-before-after-slider';

	/**
	 * The extension's WP Plugin name.
	 *
	 * @since 1.0.0
	 *
	 * @var string
	 */
	public $name = 'ds-before-after-slider';

	/**
	 * The extension's version
	 *
	 * @since 1.0.0
	 *
	 * @var string
	 */
	public $version = '1.0.0';

	/**
	 * DSS_DsBeforeAfterSlider constructor.
	 *
	 * @param string $name
	 * @param array  $args
	 */
	public function __construct( $name = 'ds-before-after-slider', $args = array() ) {
		$this->plugin_dir     = plugin_dir_path( __FILE__ );
		$this->plugin_dir_url = plugin_dir_url( $this->plugin_dir );
        $this->_builder_js_data = array(
            'defaults' => [
                'image' => "data:image/svg+xml;base64,",
            ],
        );
		parent::__construct( $name, $args );
	}
}

new DSS_DsBeforeAfterSlider;
